import java.util.*;

public class BinaryTreeDFS {
    static class TreeNode { int val; TreeNode left, right; }

    // ── Pre-order: Root → Left → Right ─────────────────────────────────────
    public static List<Integer> preOrder(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        preOrderHelper(root, result);
        return result;
    }
    private static void preOrderHelper(TreeNode node, List<Integer> res) {
        if (node == null) return;
        res.add(node.val);           // visit root FIRST
        preOrderHelper(node.left, res);
        preOrderHelper(node.right, res);
    }

    // ── In-order: Left → Root → Right (BST → sorted output) ────────────────
    public static List<Integer> inOrder(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        inOrderHelper(root, result);
        return result;
    }
    private static void inOrderHelper(TreeNode node, List<Integer> res) {
        if (node == null) return;
        inOrderHelper(node.left, res); // left subtree FIRST
        res.add(node.val);             // then root
        inOrderHelper(node.right, res);
    }

    // ── Post-order: Left → Right → Root ────────────────────────────────────
    public static List<Integer> postOrder(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        postOrderHelper(root, result);
        return result;
    }
    private static void postOrderHelper(TreeNode node, List<Integer> res) {
        if (node == null) return;
        postOrderHelper(node.left, res);
        postOrderHelper(node.right, res);
        res.add(node.val);             // root LAST
    }

    // ── Tree Height ─────────────────────────────────────────────────────────
    public static int height(TreeNode root) {
        if (root == null) return 0;
        return 1 + Math.max(height(root.left), height(root.right));
    }

    // ── Diameter of Binary Tree ─────────────────────────────────────────────
    private static int maxDiameter = 0;
    public static int diameter(TreeNode root) {
        maxDiameter = 0;
        heightForDiameter(root);
        return maxDiameter;
    }
    private static int heightForDiameter(TreeNode node) {
        if (node == null) return 0;
        int left  = heightForDiameter(node.left);
        int right = heightForDiameter(node.right);
        maxDiameter = Math.max(maxDiameter, left + right); // path through this node
        return 1 + Math.max(left, right);
    }
}

public class BST {
    static class Node { int val; Node left, right;
        Node(int v) { val = v; }
    }

    // ── Search ──────────────────────────────────────────────────────────────
    public static boolean search(Node root, int target) {
        if (root == null) return false;
        if (root.val == target) return true;
        return target < root.val
            ? search(root.left, target)
            : search(root.right, target);
    }

    // ── Insert ──────────────────────────────────────────────────────────────
    public static Node insert(Node root, int val) {
        if (root == null) return new Node(val);
        if (val < root.val) root.left  = insert(root.left,  val);
        else if (val > root.val) root.right = insert(root.right, val);
        // if val == root.val, duplicate — ignore or count
        return root;
    }

    // ── Delete ──────────────────────────────────────────────────────────────
    public static Node delete(Node root, int val) {
        if (root == null) return null;
        if (val < root.val) { root.left  = delete(root.left,  val); return root; }
        if (val > root.val) { root.right = delete(root.right, val); return root; }
        // Found the node
        if (root.left  == null) return root.right; // 0 or 1 child
        if (root.right == null) return root.left;
        // 2 children: find in-order successor (min of right subtree)
        Node successor = minNode(root.right);
        root.val = successor.val;
        root.right = delete(root.right, successor.val);
        return root;
    }

    private static Node minNode(Node node) {
        while (node.left != null) node = node.left;
        return node;
    }

    // ── Validate BST ────────────────────────────────────────────────────────
    public static boolean isValidBST(Node root) {
        return validate(root, Long.MIN_VALUE, Long.MAX_VALUE);
    }
    private static boolean validate(Node node, long min, long max) {
        if (node == null) return true;
        if (node.val <= min || node.val >= max) return false;
        return validate(node.left, min, node.val)
            && validate(node.right, node.val, max);
    }
}

public class LinkedListRunner {
    static class ListNode { int val; ListNode next; }

    // ── Cycle Detection (Floyd's Algorithm) ────────────────────────────────
    public static boolean hasCycle(ListNode head) {
        ListNode slow = head, fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
            if (slow == fast) return true;
        }
        return false;
    }

    // ── Find Cycle Start ────────────────────────────────────────────────────
    public static ListNode detectCycleStart(ListNode head) {
        ListNode slow = head, fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
            if (slow == fast) {
                slow = head; // reset slow to head
                while (slow != fast) {
                    slow = slow.next;
                    fast = fast.next;
                }
                return slow; // cycle start
            }
        }
        return null; // no cycle
    }

    // ── Find Middle Node ────────────────────────────────────────────────────
    public static ListNode findMiddle(ListNode head) {
        ListNode slow = head, fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }
        return slow; // slow is at middle
    }

    // ── Reverse a Linked List ───────────────────────────────────────────────
    public static ListNode reverse(ListNode head) {
        ListNode prev = null, curr = head;
        while (curr != null) {
            ListNode next = curr.next;
            curr.next = prev;
            prev = curr;
            curr = next;
        }
        return prev; // new head
    }

    // ── Check Palindrome ────────────────────────────────────────────────────
    public static boolean isPalindrome(ListNode head) {
        ListNode mid  = findMiddle(head);
        ListNode rev  = reverse(mid);
        ListNode copy = rev; // save for restoration
        ListNode p    = head;
        boolean  ok   = true;
        while (rev != null) {
            if (p.val != rev.val) { ok = false; break; }
            p = p.next; rev = rev.next;
        }
        reverse(copy); // restore list
        return ok;
    }
}
